// target/generated-sources/annotations/.../CustomerMapperImpl.java
@Component
public class CustomerMapperImpl implements CustomerMapper {

    @Override
    public Customer toEntity(CustomerRequest request) {
        if (request == null) {
            return null;
        }
        Customer customer = new Customer();
        customer.setName(request.getName());
        customer.setPhoneNumber(request.getPhoneNumber());
        customer.setEmail(request.getEmail());
        customer.setProductIds(request.getProductIds());
        customer.setStatus("ACTIVE");
        return customer;
    }

    @Override
    public CustomerResponse toResponse(Customer entity) {
        if (entity == null) {
            return null;
        }
        CustomerResponse response = new CustomerResponse();
        response.setId(entity.getId());
        response.setName(entity.getName());
        response.setPhoneNumber(entity.getPhoneNumber());
        response.setEmail(entity.getEmail());
        response.setStatus(entity.getStatus());
        response.setProductIds(entity.getProductIds());
        return response;
    }

    // ... otros métodos generados
}
